Функция ПолучитьДебетовыйОборот(Счет, Контрагент) Экспорт
	Запрос = Новый Запрос;
	Запрос.Текст =
	"ВЫБРАТЬ
	|	ЕСТЬNULL(СУММА(ДвиженияССубконто.Сумма), 0) КАК Сумма
	|ИЗ
	|	РегистрБухгалтерии.Хозрасчетный.ДвиженияССубконто(, , СчетДт = &Счет) КАК ДвиженияССубконто
	|ГДЕ
	|	ДвиженияССубконто.СубконтоДт1 = &Контрагент
	|	ИЛИ ДвиженияССубконто.СубконтоДт2 = &Контрагент";
	Запрос.УстановитьПараметр("Счет", Счет);
	Запрос.УстановитьПараметр("Контрагент", Контрагент);
	Выборка = Запрос.Выполнить().Выбрать();
	Выборка.Следующий();
	Возврат Выборка.Сумма;
КонецФункции
